function applyLanguage(){
  document.documentElement.lang = currentLang;
  document.querySelectorAll('[data-i18n]').forEach(el => { el.textContent = t(el.dataset.i18n); });
  document.querySelectorAll('[data-ph]').forEach(el => { el.placeholder = t(el.dataset.ph); });
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.toggle('active', b.dataset.lang === currentLang));
  renderTips(); renderOfflineLibrary(); updateUserTypeInstruction(); if(lastResult) renderResult(lastResult); if(lastHospitals.length && selectedLocation) renderHospitals(lastHospitals, selectedLocation.lat, selectedLocation.lng); if(selectedHospital) renderRouteInfo(selectedHospital);
}
document.querySelectorAll('.lang-btn').forEach(btn => btn.onclick = () => { currentLang = btn.dataset.lang; localStorage.setItem('lang', currentLang); applyLanguage(); });
$('darkBtn').onclick = () => document.body.classList.toggle('dark');

function updateUserTypeInstruction(){ const v = document.querySelector('input[name="userType"]:checked')?.value || 'Patient'; $('userTypeInstruction').textContent = userInstructions[currentLang]?.[v] || userInstructions.en[v]; }
document.querySelectorAll('input[name="userType"]').forEach(r => r.onchange = updateUserTypeInstruction);
function renderTips(){ $('tipsList').innerHTML = t('tips').map(x => `<li>${escapeHtml(x)}</li>`).join(''); }

function listInto(id, arr){ $(id).innerHTML = (arr || []).map(x => `<li>${escapeHtml(x)}</li>`).join(''); }
function getPayload(){ return { name: val('name') || 'User', age:num('age'), gender:val('gender'), user_type:document.querySelector('input[name="userType"]:checked')?.value || 'Patient', village:val('village'), phone:val('phone'), emergency_contact:val('emergencyContact'), blood_group:val('bloodGroup'), existing_diseases:val('existingDiseases'), current_medicines:val('currentMedicines'), symptoms:val('symptoms'), duration:val('duration'), temperature:num('temperature'), spo2:num('spo2'), pulse:num('pulse'), bp_systolic:num('bpSys'), bp_diastolic:num('bpDia'), diabetes:$('diabetes').checked, pregnancy:$('pregnancy').checked, child_patient:$('childPatient').checked, allergy_type:val('allergyType'), allergy:val('allergy') || (val('allergyType') !== 'No' ? val('allergyType') : ''), language:currentLang, latitude:selectedLocation?.lat || null, longitude:selectedLocation?.lng || null }; }
$('analyzeBtn').onclick = analyze;
async function analyze(){
  const payload = getPayload(); if(!payload.symptoms){ alert(t('enterSymptoms')); return; }
  const res = await fetch('/api/analyze',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});
  lastResult = await res.json(); renderResult(lastResult); savePatientHistory(lastResult); loadLogs(); loadAdminSummary(); renderHistory(); $('resultCard').classList.remove('hidden'); scrollToId('resultCard'); speak(lastResult.voice_reply);
}
function renderResult(data){
  $('emergencyMsg').textContent = data.emergency_message || '';
  $('riskPill').textContent = `${data.risk.risk_level}`;
  $('riskPill').style.background = riskColors[data.risk.level_key] || '#0f766e';
  $('scoreBar').style.width = `${data.risk.score}%`; $('scoreText').textContent = `${data.risk.score}/100`; if($('caseIdText')) $('caseIdText').textContent=data.case_id||'-'; if($('confidenceText')) $('confidenceText').textContent=(data.ai_confidence?data.ai_confidence+'%':'-');
  listInto('factorList', [...(data.risk.factors||[]), ...((data.ai_explanation||[]).map(x=>'AI: '+x))]); listInto('firstAidList', data.first_aid); listInto('medicineList', [...(data.medicine_guidance.suggestions||[]), ...(data.medicine_guidance.warnings||[])]); $('doctorWarning').textContent = data.doctor_warning || t('medicineSafety'); listInto('nextSteps', data.next_steps); renderEmergencyProfile(data); updateSafetyAlert();
}
$('speakResultBtn').onclick = () => lastResult ? speak(lastResult.voice_reply) : speak(t('analyzeFirst'));
$('speakBtn').onclick = () => lastResult ? speak(lastResult.voice_reply) : speak(t('analyzeFirst'));
$('speakAidBtn').onclick = () => lastResult && speak(lastResult.first_aid.join('. '));
$('speakMedBtn').onclick = () => lastResult && speak([t('medicineSafety'), ...(lastResult.medicine_guidance.suggestions||[]), ...(lastResult.medicine_guidance.warnings||[])].join('. '));

async function playServerTTS(text){
  try{ $('voiceStatus').textContent = '🔊 ' + t('preparingVoice'); const res = await fetch('/api/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({text,language:currentLang})}); if(!res.ok) throw new Error('TTS failed'); const blob = await res.blob(); const url = URL.createObjectURL(blob); if(currentAudio) currentAudio.pause(); currentAudio = new Audio(url); currentAudio.onended = () => URL.revokeObjectURL(url); await currentAudio.play(); $('voiceStatus').textContent = '🔊 ' + t('voiceSpeaking'); return true; } catch(e){ $('voiceStatus').textContent = '⚠️ ' + t('onlineVoiceFailed'); return false; }
}
async function speak(text){ if(!text) return; if(currentLang === 'kn' || currentLang === 'te'){ if(await playServerTTS(text)) return; } if('speechSynthesis' in window){ speechSynthesis.cancel(); const u = new SpeechSynthesisUtterance(text); u.lang = currentLang==='kn'?'kn-IN':currentLang==='te'?'te-IN':'en-IN'; u.rate = .88; speechSynthesis.speak(u); } }
function startVoice(){ const SR = window.SpeechRecognition || window.webkitSpeechRecognition; if(!SR){ alert(t('voiceNotSupported')); return; } const rec = new SR(); rec.lang = currentLang==='kn'?'kn-IN':currentLang==='te'?'te-IN':'en-IN'; rec.interimResults = false; rec.continuous = false; $('voiceStatus').textContent = t('listening'); speak(t('listening')); rec.start(); rec.onresult = e => { const text = e.results[0][0].transcript; $('symptoms').value = ($('symptoms').value + ' ' + text).trim(); $('voiceStatus').textContent = t('heard') + ': ' + text; speak(t('noted')); }; rec.onerror = e => { $('voiceStatus').textContent = t('voiceError') + ': ' + e.error; }; }
$('voiceBtn').onclick = startVoice;

function initMap(lat=13.0827,lng=77.5877){ if(map) return; map = L.map('map').setView([lat,lng],13); L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19, attribution:'© OpenStreetMap'}).addTo(map); hospitalLayer = L.layerGroup().addTo(map); }
initMap();
$('locationBtn').onclick = () => { if(!navigator.geolocation){ $('locationStatus').textContent = t('geolocationUnsupported'); return; } $('locationStatus').textContent = t('locationGetting'); navigator.geolocation.getCurrentPosition(async pos => { const lat = pos.coords.latitude, lng = pos.coords.longitude; $('locationStatus').textContent = `${t('locatingName')} (${lat.toFixed(6)}, ${lng.toFixed(6)})`; const name = await reverseGeocode(lat,lng); selectedLocation = {lat,lng,label:name || `${lat.toFixed(6)}, ${lng.toFixed(6)}`}; $('locationStatus').textContent = `${t('liveLocationFound')}: ${selectedLocation.label}`; showUser(lat,lng,selectedLocation.label); await findHospitals(lat,lng); }, err => { $('locationStatus').textContent = t('permissionFailed') + ' ' + err.message; }, {enableHighAccuracy:true,timeout:20000,maximumAge:0}); };
$('shareLocationTop').onclick = () => shareLocation();
async function reverseGeocode(lat,lng){ try{ const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lng}&zoom=16&addressdetails=1`); const d = await res.json(); return d.display_name || ''; }catch(e){ return ''; } }
$('manualLocationBtn').onclick = manualLocationSearch; $('manualLocation').addEventListener('keydown', e => { if(e.key==='Enter') manualLocationSearch(); });
async function manualLocationSearch(){ const q = val('manualLocation'); if(!q){ alert(t('enterLocation')); return; } $('locationStatus').textContent = `${t('searchingLocation')}: ${q}`; try{ const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q)}&limit=1`); const data = await res.json(); if(!data.length){ $('locationStatus').textContent = t('locationNotFound'); return; } const lat = Number(data[0].lat), lng = Number(data[0].lon); selectedLocation = {lat,lng,label:data[0].display_name}; $('locationStatus').textContent = `${t('manualSelected')}: ${data[0].display_name}`; showUser(lat,lng,data[0].display_name); await findHospitals(lat,lng); } catch(e){ $('locationStatus').textContent = t('hospitalLoadFail'); } }
function showUser(lat,lng,label){ initMap(lat,lng); map.setView([lat,lng],15); if(userMarker) userMarker.remove(); userMarker = L.marker([lat,lng]).addTo(map).bindPopup(label || t('youAreHere')).openPopup(); }
async function findHospitals(lat,lng){ hospitalLayer.clearLayers(); if(routeLine){ routeLine.remove(); routeLine = null; } $('routeInfo').classList.add('hidden'); $('hospitalList').innerHTML = '<p class="muted">'+t('searchHosp')+'</p>'; const radius = $('radius').value; const q = `[out:json][timeout:25];(node["amenity"~"hospital|clinic|doctors"](around:${radius},${lat},${lng});way["amenity"~"hospital|clinic|doctors"](around:${radius},${lat},${lng});relation["amenity"~"hospital|clinic|doctors"](around:${radius},${lat},${lng}););out center tags 30;`; try{ const eps = ['https://overpass-api.de/api/interpreter','https://overpass.kumi.systems/api/interpreter','https://overpass.openstreetmap.ru/api/interpreter']; let data = null; for(const ep of eps){ try{ const r = await fetch(ep,{method:'POST',body:q,headers:{'Content-Type':'text/plain;charset=UTF-8'}}); if(r.ok){ data = await r.json(); break; } }catch(e){} } if(!data) throw new Error('overpass failed'); let hospitals = data.elements.map(e => ({name:e.tags?.name || t('unnamedHospital'), type:e.tags?.amenity || 'medical', lat:e.lat || e.center?.lat, lng:e.lon || e.center?.lon, phone:e.tags?.phone || e.tags?.['contact:phone'] || '', addr:[e.tags?.['addr:housenumber'], e.tags?.['addr:street'], e.tags?.['addr:city'], e.tags?.['addr:district']].filter(Boolean).join(', ')})).filter(h => h.lat && h.lng); hospitals = hospitals.map(h => ({...h, dist:distanceKm(lat,lng,h.lat,h.lng)})).sort((a,b)=>a.dist-b.dist).slice(0,12); lastHospitals = hospitals; renderHospitals(hospitals,lat,lng); } catch(e){ $('hospitalList').innerHTML = `<p class="warning">${t('hospitalLoadFail')}</p><button onclick="openHospitalSearch(${lat},${lng})">${t('openMaps')}</button>`; } }
function distanceKm(a,b,c,d){ const R=6371,toRad=x=>x*Math.PI/180,dLat=toRad(c-a),dLon=toRad(d-b),aa=Math.sin(dLat/2)**2+Math.cos(toRad(a))*Math.cos(toRad(c))*Math.sin(dLon/2)**2; return R*2*Math.atan2(Math.sqrt(aa),Math.sqrt(1-aa)); }
function renderHospitals(hospitals,ulat,ulng){ if(!hospitals.length){ $('hospitalList').innerHTML = '<p class="warning">'+t('noHosp')+'</p>'; return; } $('hospitalList').innerHTML = hospitals.map((h,i) => `<div class="hospital"><h4>${i+1}. ${escapeHtml(h.name)}</h4><div class="hospital-meta"><span>🏥 ${escapeHtml(h.type)}</span><span>📏 ${h.dist.toFixed(2)} km</span></div><p><b>${t('address')}:</b> ${escapeHtml(h.addr || '-')}</p><div class="hospital-actions"><button onclick='routeTo(${ulat},${ulng},${h.lat},${h.lng},${JSON.stringify(h.name)},${h.dist})'>${t('showRoute')}</button><button onclick="openMaps(${ulat},${ulng},${h.lat},${h.lng})">${t('openMaps')}</button><a class="mini-call" href="tel:${h.phone || 108}">${h.phone ? t('callHospital') : t('call108')}</a></div></div>`).join(''); hospitals.forEach((h,i)=>L.marker([h.lat,h.lng]).addTo(hospitalLayer).bindPopup(`${i+1}. ${escapeHtml(h.name)}<br>${h.dist.toFixed(2)} km`)); }
window.openMaps = (a,b,c,d) => window.open(`https://www.google.com/maps/dir/${a},${b}/${c},${d}`,'_blank');
window.openHospitalSearch = (a,b) => window.open(`https://www.google.com/maps/search/hospitals+near+me/@${a},${b},14z`,'_blank');
window.routeTo = async(a,b,c,d,name,dist) => { selectedHospital = {name,dist,ulat:a,ulng:b,lat:c,lng:d}; renderRouteInfo(selectedHospital); try{ const res = await fetch(`https://router.project-osrm.org/route/v1/driving/${b},${a};${d},${c}?overview=full&geometries=geojson`); const data = await res.json(); const coords = data.routes[0].geometry.coordinates.map(x=>[x[1],x[0]]); const routeDist = data.routes[0].distance/1000, min = Math.round(data.routes[0].duration/60); selectedHospital.dist = routeDist; selectedHospital.minutes = min; renderRouteInfo(selectedHospital); if(routeLine) routeLine.remove(); routeLine = L.polyline(coords,{weight:6}).addTo(map); map.fitBounds(routeLine.getBounds()); }catch(e){} speak(lastRouteText); };
function renderRouteInfo(h){ const mins = h.minutes || Math.max(3, Math.round((h.dist/30)*60)); lastRouteText = `${t('routeReady')} ${t('hospitalName')}: ${h.name}. ${t('distance')}: ${h.dist.toFixed(2)} km. ${t('estimatedTime')}: ${mins} minutes. ${t('clickOpenRoute')}`; $('routeInfo').innerHTML = `<b>${t('routeReady')}</b><br>${t('hospitalName')}: ${escapeHtml(h.name)}<br>${t('distance')}: ${h.dist.toFixed(2)} km<br>${t('estimatedTime')}: ${mins} minutes<br><button onclick="openMaps(${h.ulat},${h.ulng},${h.lat},${h.lng})">${t('openMaps')}</button>`; $('routeInfo').classList.remove('hidden'); }
$('speakRouteBtn').onclick = () => lastRouteText ? speak(lastRouteText) : speak(t('pressLocation'));
function shareLocation(){ const text = selectedLocation ? `${t('selectedLocation')}: ${selectedLocation.label} https://www.google.com/maps?q=${selectedLocation.lat},${selectedLocation.lng}` : t('pressLocation'); shareText(text); }

function offlineKey(sym){ const s = (sym||'').toLowerCase(); if(/chest|heart|ಛಾತಿ|ಎದೆ|ఛాతి/.test(s)) return 'chest'; if(/breath|asthma|oxygen|ಉಸಿರ|శ్వాస/.test(s)) return 'breathing'; if(/bleed|blood|cut|wound|ರಕ್ತ|గాయం|రక్త/.test(s)) return 'bleeding'; if(/burn|fire|hot|ಸುಟ್ಟ|కాలిన/.test(s)) return 'burn'; if(/snake|bite|ಪಾಮು|పాము/.test(s)) return 'snake'; if(/accident|ಅಪಘಾತ|ప్రమాదం/.test(s)) return 'accident'; if(/unconscious|faint|ಪ್ರಜ್ಞೆ|స్పృహ/.test(s)) return 'unconscious'; if(/seizure|fits|ಮೂರ್ಚೆ|మూర్ఛ/.test(s)) return 'seizure'; if(/fracture|bone|ಮೂಳೆ|ఎముక/.test(s)) return 'fracture'; if(/cough|cold|ಕೆಮ್ಮು|దగ్గు|జలుబు/.test(s)) return 'cough'; return 'fever'; }
const offlineKeys = ['chest','breathing','bleeding','burn','snake','fever','accident','unconscious','seizure','fracture'];
function renderOfflineLibrary(){ if($('offlineLibrary')) $('offlineLibrary').innerHTML = ''; }
window.showOffline = key => { const db = offlineDB[currentLang] || offlineDB.en, item = db[key] || db.fever; $('offlineTitleResult').textContent = item.title; listInto('offlineDoList', item.do); listInto('offlineDontList', item.dont); listInto('offlineCallList', item.call); listInto('offlineMedicineList', item.meds); $('offlineWarn').textContent = t('offlineWarn'); };
$('offlineAnalyzeBtn').onclick = () => { const s = val('offlineSymptoms'); if(!s){ alert(t('enterSymptoms')); return; } const key = offlineKey(s); showOffline(key); speak([$('offlineTitleResult').textContent, ...Array.from($('offlineDoList').children).map(li=>li.textContent), ...Array.from($('offlineMedicineList').children).map(li=>li.textContent), t('offlineWarn')].join('. ')); };
$('speakOfflineBtn').onclick = () => speak([$('offlineTitleResult').textContent, ...Array.from($('offlineDoList').children).map(li=>li.textContent), ...Array.from($('offlineDontList').children).map(li=>li.textContent), ...Array.from($('offlineCallList').children).map(li=>li.textContent), ...Array.from($('offlineMedicineList').children).map(li=>li.textContent)].join('. '));

function reportText(){ const p = getPayload(), r = lastResult; return `AI-Powered Rural Emergency Medical Assistant\nDate/Time: ${new Date().toLocaleString()}\n\nPatient Details\nName: ${p.name}\nAge: ${p.age || '-'}\nGender: ${p.gender || '-'}\nVillage: ${p.village || '-'}\nPhone: ${p.phone || '-'}\nEmergency Contact: ${p.emergency_contact || '-'}\nBlood Group: ${p.blood_group || '-'}\nUser Type: ${p.user_type}\nExisting Diseases: ${p.existing_diseases || '-'}\nCurrent Medicines: ${p.current_medicines || '-'}\nAllergy: ${p.allergy || '-'}\nPregnancy: ${p.pregnancy ? 'Yes' : 'No'}\nChild below 12: ${p.child_patient ? 'Yes' : 'No'}\nSymptoms: ${p.symptoms || '-'}\nDuration: ${p.duration || '-'}\n\nRisk Level: ${r?.risk?.risk_level || '-'}\nRisk Score: ${r?.risk?.score ?? '-'} / 100\nMessage: ${r?.emergency_message || '-'}\n\nFirst-Aid Steps\n${(r?.first_aid||[]).map((x,i)=>`${i+1}. ${x}`).join('\n')}\n\nMedicine Guidance\n${(r?.medicine_guidance?.suggestions||[]).map((x,i)=>`${i+1}. ${x}`).join('\n')}\n\nWarnings\n${[r?.doctor_warning, ...(r?.medicine_guidance?.warnings||[])].filter(Boolean).map((x,i)=>`${i+1}. ${x}`).join('\n')}\n\nNearest Hospital\n${selectedHospital ? `${selectedHospital.name}\nDistance: ${selectedHospital.dist.toFixed(2)} km\nGoogle Maps: https://www.google.com/maps/dir/${selectedHospital.ulat},${selectedHospital.ulng}/${selectedHospital.lat},${selectedHospital.lng}` : 'Not selected'}\n\nThis is an educational prototype. Call 108 for serious emergencies.`; }
function downloadReport(){ if(!lastResult){ alert(t('analyzeFirst')); return; } const blob = new Blob([reportText()], {type:'text/plain;charset=utf-8'}); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `emergency_report_${Date.now()}.txt`; a.click(); $('doctorStatus').textContent = t('reportDownloaded'); }
$('downloadReportBtn').onclick = downloadReport; $('downloadPatientReportBtn').onclick = downloadReport;
$('sendReportBtn').onclick = () => { if(!lastResult){ alert(t('analyzeFirst')); return; } shareText(reportText()); $('doctorStatus').textContent = t('reportShared'); };
$('shareEmergencyBtn').onclick = () => lastResult ? shareText(reportText()) : alert(t('analyzeFirst'));
$('requestDoctorBtn').onclick = () => { $('doctorStatus').textContent = t('doctorRequest'); speak(t('doctorRequest')); };
async function shareText(text){ if(navigator.share){ try{ await navigator.share({title:'Emergency Medical Report', text}); return; }catch(e){} } try{ await navigator.clipboard.writeText(text); alert(t('copied')); } catch(e){ alert(t('shareNotSupported')); } }

async function loadLogs(){ try{ const res = await fetch('/api/logs'); const logs = await res.json(); $('totalCases').textContent = logs.length; $('criticalCases').textContent = logs.filter(x=>x.risk?.level_key==='critical').length; $('highCases').textContent = logs.filter(x=>x.risk?.level_key==='high').length; const symptoms = logs.map(x => (x.patient?.village || x.symptoms || x.emergency_message || '')).filter(Boolean); $('commonSymptoms').textContent = logs.length ? (logs[logs.length-1].risk?.matched?.[0] || '-') : '-'; const villages = {}; logs.forEach(l => { const v = l.patient?.village; if(v) villages[v] = (villages[v]||0)+1; }); $('topVillage').textContent = Object.entries(villages).sort((a,b)=>b[1]-a[1])[0]?.[0] || '-'; const c = {C:logs.filter(x=>x.risk?.level_key==='critical').length,H:logs.filter(x=>x.risk?.level_key==='high').length,M:logs.filter(x=>x.risk?.level_key==='medium').length,L:logs.filter(x=>x.risk?.level_key==='low').length}; $('riskChart').textContent = `C:${c.C} H:${c.H} M:${c.M} L:${c.L}`; $('recentLogs').innerHTML = logs.slice(-8).reverse().map(l => `<div class="log-item"><b>${escapeHtml(l.patient?.name || 'User')}</b> • ${escapeHtml(l.risk?.risk_level || '')} • ${l.risk?.score}/100<br><span class="muted">${escapeHtml(l.patient?.village || '-')} • ${escapeHtml(l.timestamp || '')}</span></div>`).join('') || '<p class="muted">'+t('noLogs')+'</p>'; }catch(e){} }
$('refreshLogs').onclick = loadLogs; $('clearLogs').onclick = async()=>{ await fetch('/api/logs',{method:'DELETE'}); loadLogs(); };
$('exportCsv').onclick = async()=>{ const res = await fetch('/api/logs'); const logs = await res.json(); const rows = ['time,name,age,village,risk,score,message', ...logs.map(l => [l.timestamp,l.patient?.name,l.patient?.age,l.patient?.village,l.risk?.risk_level,l.risk?.score,(l.emergency_message||'').replaceAll(',',' ')].join(','))]; const blob = new Blob([rows.join('\n')], {type:'text/csv'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='emergency_logs.csv'; a.click(); };


