function updateSafetyAlert(){
  const warns=[];
  if(val('allergyType') !== 'No' || val('allergy')) warns.push('⚠️ '+t('allergyWarning'));
  if($('pregnancy')?.checked || $('childPatient')?.checked || (num('age')!==null && num('age')<12)) warns.push('⚠️ '+t('childPregWarn'));
  if($('safetyAlert')) $('safetyAlert').innerHTML = warns.map(escapeHtml).join('<br>');
}
['allergyType','allergy','pregnancy','childPatient','age'].forEach(id => { if($(id)) $(id).addEventListener('input', updateSafetyAlert); if($(id)) $(id).addEventListener('change', updateSafetyAlert); });

function renderEmergencyProfile(data){
  const p = getPayload();
  $('profileCard').classList.remove('hidden');
  $('profileCard').innerHTML = `<h4>🪪 ${t('profileTitle')}</h4><div class="profile-grid"><span>${t('name')}: <b>${escapeHtml(p.name)}</b></span><span>${t('age')}: <b>${p.age || '-'}</b></span><span>${t('bloodGroup')}: <b>${escapeHtml(p.blood_group || '-')}</b></span><span>${t('village')}: <b>${escapeHtml(p.village || '-')}</b></span><span>${t('phone')}: <b>${escapeHtml(p.phone || '-')}</b></span><span>${t('emergencyContact')}: <b>${escapeHtml(p.emergency_contact || '-')}</b></span><span>${t('allergy')}: <b>${escapeHtml(p.allergy || '-')}</b></span><span>${t('currentMedicines')}: <b>${escapeHtml(p.current_medicines || '-')}</b></span></div>`;
}

const visualSymptoms = [
  ['🤒','Fever','ಜ್ವರ','జ్వరం'], ['🤧','Cough','ಕೆಮ್ಮು','దగ్గు'], ['❤️','Chest Pain','ಎದೆ ನೋವು','ఛాతి నొప్పి'], ['🫁','Breathing Problem','ಉಸಿರಾಟ ತೊಂದರೆ','శ్వాస ఇబ్బంది'], ['🩸','Bleeding','ರಕ್ತಸ್ರಾವ','రక్తస్రావం'], ['🔥','Burns','ಸುಟ್ಟ ಗಾಯ','కాలిన గాయం'], ['🐍','Snake Bite','ಪಾಮು ಕಚ್ಚು','పాము కాటు'], ['🤢','Vomiting','ವಾಂತಿ','వాంతి'], ['😵','Dizziness','ತಲೆ ಸುತ್ತು','తల తిరగడం'], ['🚑','Accident','ಅಪಘಾತ','ప్రమాదం'], ['🦴','Fracture','ಮೂಳೆ ಮುರಿತ','ఎముక విరగడం']
];
function renderVisualSymptoms(){
  if(!$('visualSymptomButtons')) return;
  const langIndex = currentLang==='kn'?2:currentLang==='te'?3:1;
  $('visualSymptomButtons').innerHTML = visualSymptoms.map(v => `<button type="button" onclick="addVisualSymptom('${escapeHtml(v[langIndex])}')"><span>${v[0]}</span>${escapeHtml(v[langIndex])}</button>`).join('');
}
window.addVisualSymptom = txt => { $('offlineSymptoms').value = ($('offlineSymptoms').value ? $('offlineSymptoms').value + ', ' : '') + txt; const key=offlineKey(txt); showOffline(key); };

async function generateQr(){
  if(!lastResult){ alert(t('analyzeFirst')); return; }
  const text = reportText().slice(0,1100);
  $('qrImage').src = '/api/qr?text=' + encodeURIComponent(text);
  $('qrPanel').classList.remove('hidden');
}
if($('qrBtn')) $('qrBtn').onclick = generateQr;

async function loadPharmacies(){
  if(!selectedLocation){ alert(t('pressLocation')); return; }
  const lat=selectedLocation.lat, lng=selectedLocation.lng, radius=Number(val('radius') || 5000);
  $('pharmacyList').innerHTML = `<p class="muted">${t('searchingLocation')}...</p>`;
  const query = `[out:json][timeout:20];(node["amenity"="pharmacy"](around:${radius},${lat},${lng});way["amenity"="pharmacy"](around:${radius},${lat},${lng});relation["amenity"="pharmacy"](around:${radius},${lat},${lng}););out center tags 20;`;
  try{
    const res = await fetch('https://overpass-api.de/api/interpreter',{method:'POST',body:query});
    const data = await res.json();
    const items = (data.elements||[]).map(e=>{ const elat=e.lat || e.center?.lat, elng=e.lon || e.center?.lon; return {name:e.tags?.name || 'Medical Store / Pharmacy', addr:e.tags?.['addr:full'] || e.tags?.['addr:street'] || '', lat:elat, lng:elng, dist:distanceKm(lat,lng,elat,elng)}; }).filter(x=>x.lat&&x.lng).sort((a,b)=>a.dist-b.dist).slice(0,8);
    if(!items.length){ $('pharmacyList').innerHTML = `<p class="warning">${t('noPharmacies')}</p>`; return; }
    $('pharmacyList').innerHTML = items.map((p,i)=>`<div class="hospital"><h4>${i+1}. ${escapeHtml(p.name)}</h4><div class="hospital-meta"><span>💊 Pharmacy</span><span>📏 ${p.dist.toFixed(2)} km</span></div><p><b>${t('address')}:</b> ${escapeHtml(p.addr || '-')}</p><div class="hospital-actions"><button onclick="openMaps(${lat},${lng},${p.lat},${p.lng})">${t('openMaps')}</button></div></div>`).join('');
    window.lastPharmacyText = items.slice(0,3).map((p,i)=>`${i+1}. ${p.name}, ${p.dist.toFixed(2)} km`).join('. ');
  }catch(e){ $('pharmacyList').innerHTML = `<p class="warning">${t('pharmacyLoadFail')}</p><button onclick="window.open('https://www.google.com/maps/search/pharmacy+near+me/@${lat},${lng},14z','_blank')">${t('openMaps')}</button>`; }
}
if($('pharmacyBtn')) $('pharmacyBtn').onclick = loadPharmacies;
if($('speakPharmacyBtn')) $('speakPharmacyBtn').onclick = () => speak(window.lastPharmacyText || t('pressLocation'));

function getHistory(){ try{return JSON.parse(localStorage.getItem('patientHistory')||'[]')}catch(e){return[]} }
function savePatientHistory(item){ const h=getHistory(); h.push(item); localStorage.setItem('patientHistory', JSON.stringify(h.slice(-50))); }
function renderHistory(){
  if(!$('historyList')) return; const h=getHistory();
  $('historyList').innerHTML = h.slice(-10).reverse().map((l,idx)=>`<div class="log-item"><b>${escapeHtml(l.patient?.name||'User')}</b> • ${escapeHtml(l.risk?.risk_level||'')} • ${l.risk?.score}/100<br><span class="muted">${escapeHtml(l.patient?.village||'-')} • ${escapeHtml(l.timestamp||'')}</span><br><button onclick="downloadHistoryReport(${h.length-1-idx})">${t('downloadReport')}</button></div>`).join('') || `<p class="muted">${t('noHistory')}</p>`;
}
window.downloadHistoryReport = i => { const h=getHistory(); const old=lastResult; lastResult=h[i]; if(lastResult) downloadReport(); lastResult=old; };
if($('refreshHistory')) $('refreshHistory').onclick = renderHistory;
if($('clearHistory')) $('clearHistory').onclick = () => { localStorage.removeItem('patientHistory'); renderHistory(); };

function workerCases(){ try{return JSON.parse(localStorage.getItem('workerCases')||'[]')}catch(e){return[]} }
function renderWorkerCases(){ const cases=workerCases(); if(!$('workerCases')) return; $('workerCases').innerHTML = cases.slice(-10).reverse().map(c=>`<div class="log-item"><b>${escapeHtml(c.name)}</b> • ${escapeHtml(c.village)}<br><span class="muted">${escapeHtml(c.symptom)} • ${escapeHtml(c.time)}</span></div>`).join('') || '<p class="muted">No village cases yet.</p>'; }
if($('addWorkerCase')) $('addWorkerCase').onclick = () => { const cases=workerCases(); cases.push({name:val('workerPatientName')||'Patient', village:val('workerVillage')||val('village')||'-', symptom:val('workerSymptom')||'-', time:new Date().toLocaleString()}); localStorage.setItem('workerCases',JSON.stringify(cases.slice(-100))); renderWorkerCases(); };
if($('exportVillageReport')) $('exportVillageReport').onclick = () => { const rows=['name,village,symptom,time',...workerCases().map(c=>[c.name,c.village,c.symptom,c.time].join(','))]; const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([rows.join('\n')],{type:'text/csv'})); a.download='village_health_worker_report.csv'; a.click(); };

async function loadAdminSummary(){
  try{ const res=await fetch('/api/admin-summary'); const d=await res.json(); $('adminPatients').textContent=d.total_patients; $('adminEmergencies').textContent=d.total_emergencies; $('adminCritical').textContent=d.critical_cases; $('adminVillages').textContent=d.villages_covered; $('adminSymptom').textContent=d.common_symptom; $('adminOutbreak').textContent=d.outbreak_status; $('outbreakAlert').innerHTML = d.outbreak_status && d.outbreak_status !== 'Normal' ? `🚨 <b>${t('possibleOutbreak')}</b><br>${escapeHtml(d.outbreak_status)}` : `✅ ${t('normalStatus')}`; }catch(e){}
}

const oldApplyLanguage = applyLanguage;
applyLanguage = function(){ oldApplyLanguage(); renderVisualSymptoms(); updateSafetyAlert(); renderHistory(); renderWorkerCases(); loadAdminSummary(); };

applyLanguage(); renderOfflineLibrary(); showOffline('chest'); loadLogs(); renderVisualSymptoms(); renderHistory(); renderWorkerCases(); loadAdminSummary();
if('serviceWorker' in navigator) navigator.serviceWorker.register('/service-worker.js').catch(()=>{});


