Object.assign(i18n.te,{caseId:'అత్యవసర కేసు ID',aiConfidence:'AI నమ్మకం',ambulanceTracking:'అంబులెన్స్ ట్రాకింగ్ సిమ్యులేషన్',ambulanceText:'అంబులెన్స్ అభ్యర్థన, డ్రైవర్, వాహన నంబర్ మరియు అంచనా రాక సమయాన్ని చూపిస్తుంది.',requestAmbulance:'అంబులెన్స్ కోరండి',whatsappAlert:'WhatsApp హెచ్చరిక పంపండి',medicineReminder:'ఆటోమేటిక్ మందుల రిమైండర్',medicineReminderText:'విశ్లేషణ తర్వాత మందుల మార్గదర్శకం ఆధారంగా రిమైండర్లు తయారవుతాయి. డాక్టర్ సలహా తర్వాత మాత్రమే అనుసరించండి.',videoGuide:'ఫస్ట్ ఎయిడ్ వీడియో గైడ్',videoGuideText:'గ్రామస్తులు మరియు ఆరోగ్య కార్యకర్తల కోసం త్వరిత వీడియో లింకులు.',caseLookup:'అత్యవసర ID శోధన',caseLookupText:'సేవ్ చేసిన రోగి రికార్డ్ చూడటానికి అత్యవసర ID నమోదు చేయండి.',lookupRecord:'రోగి రికార్డ్ చూపించు',multiPatientRegister:'మల్టీ-పేషెంట్ రిజిస్టర్',multiPatientText:'గ్రామ ఆరోగ్య కార్యకర్తలు అనేక రోగులను జోడించి, వెతికి, ఎగుమతి చేయవచ్చు.',addPatient:'రోగిని జోడించండి',exportPatientList:'రోగుల జాబితా ఎగుమతి',emergencyHeatmap:'అత్యవసర హీట్‌మ్యాప్',heatmapText:'వ్యాధి వ్యాప్తి పర్యవేక్షణకు గ్రామాల వారీ కేసుల సంఖ్య.',riskTrendChart:'రిస్క్ ట్రెండ్ చార్ట్',riskTrendText:'లో, మీడియం, హై, క్రిటికల్ కేసుల విజువల్ సారాంశం.',ambulanceAssigned:'అంబులెన్స్ కేటాయించబడింది',driver:'డ్రైవర్',vehicle:'వాహనం',eta:'అంచనా రాక',statusOnWay:'వస్తోంది',reminderAt:'రిమైండర్',patientAdded:'రోగి జోడించబడింది',recordNotFound:'రికార్డ్ దొరకలేదు'});

function makeWhatsAppText(){
  const p=getPayload(), r=lastResult; const loc=selectedLocation?.label || p.village || '-';
  return `Emergency Alert!\nCase ID: ${r?.case_id||'-'}\nPatient: ${p.name||'User'}\nSymptoms: ${p.symptoms||'-'}\nRisk Level: ${r?.risk?.risk_level||'-'}\nScore: ${r?.risk?.score||'-'}/100\nLocation: ${loc}\nPlease respond immediately.`;
}
function openWhatsApp(){ const text=encodeURIComponent(makeWhatsAppText()); window.open(`https://wa.me/?text=${text}`,'_blank'); }
if($('whatsappAlertBtn')) $('whatsappAlertBtn').onclick=openWhatsApp;
if($('requestAmbulanceBtn')) $('requestAmbulanceBtn').onclick=()=>{
  const drivers=['Ravi Kumar','Manjunath S','Suresh Reddy','Anil Kumar','Ramesh Gowda']; const driver=drivers[Math.floor(Math.random()*drivers.length)]; const eta=Math.max(6,Math.round((selectedHospital?.dist||4)*3+4));
  $('ambulanceStatus').innerHTML=`<b>🚑 ${t('ambulanceAssigned')}</b><br>${t('driver')}: <b>${driver}</b><br>${t('vehicle')}: <b>KA-${Math.floor(10+Math.random()*80)}-A-${Math.floor(1000+Math.random()*8999)}</b><br>${t('eta')}: <b>${eta} minutes</b><br>${t('statusOnWay')}: ✅`;
  speak(`${t('ambulanceAssigned')}. ${t('eta')} ${eta} minutes.`);
};
function renderMedicineReminders(data){
  if(!$('medicineReminderList')) return; const meds=(data?.medicine_guidance?.suggestions||[]).slice(0,4);
  if(!meds.length){$('medicineReminderList').innerHTML='<p class="muted">'+t('analyzeFirst')+'</p>';return;}
  const times=['08:00 AM','02:00 PM','08:00 PM','Before sleep'];
  $('medicineReminderList').innerHTML=meds.map((m,i)=>`<div class="reminder-card"><b>💊 ${t('reminderAt')} ${times[i]||times[0]}</b><br>${escapeHtml(m)}<br><small>${t('medicineSafety')}</small></div>`).join('');
}
function renderVideos(){
  if(!$('videoGuideList')) return; const vids=[['❤️','CPR / Chest Pain','https://www.youtube.com/results?search_query=CPR+first+aid'],['🩸','Bleeding Control','https://www.youtube.com/results?search_query=bleeding+control+first+aid'],['🔥','Burns First Aid','https://www.youtube.com/results?search_query=burns+first+aid'],['🐍','Snake Bite First Aid','https://www.youtube.com/results?search_query=snake+bite+first+aid'],['🦴','Fracture Support','https://www.youtube.com/results?search_query=fracture+first+aid']];
  $('videoGuideList').innerHTML=vids.map(v=>`<a class="video-card" target="_blank" href="${v[2]}"><span>${v[0]}</span>${v[1]}<small>Open video guide</small></a>`).join('');
}
async function lookupCase(){
  const id=val('lookupCaseId'); if(!id){alert('Enter Case ID');return;} $('lookupResult').innerHTML='<p class="muted">Searching...</p>';
  const res=await fetch('/api/record/'+encodeURIComponent(id)); if(!res.ok){$('lookupResult').innerHTML='<p class="warning">'+t('recordNotFound')+'</p>';return;}
  const r=await res.json(); const p=r.patient||{}; $('lookupResult').innerHTML=`<div class="lookup-card"><b>${escapeHtml(r.case_id||'')}</b><br>${t('name')}: ${escapeHtml(p.name||'-')} • ${t('village')}: ${escapeHtml(p.village||'-')}<br>${t('symptoms')}: ${escapeHtml(r.symptoms||'-')}<br>${t('riskScoreLabel')} ${escapeHtml(r.risk?.risk_level||'-')} ${r.risk?.score||'-'}/100<br>${t('firstAid')}: ${(r.first_aid||[]).slice(0,2).map(escapeHtml).join('; ')}</div>`;
}
if($('lookupCaseBtn')) $('lookupCaseBtn').onclick=lookupCase;
function patients(){try{return JSON.parse(localStorage.getItem('multiPatients')||'[]')}catch(e){return[]}}
function savePatients(a){localStorage.setItem('multiPatients',JSON.stringify(a.slice(-200)))}
function renderPatients(){ if(!$('multiPatientList'))return; const q=(val('patientSearch')||'').toLowerCase(); const a=patients().filter(p=>!q||JSON.stringify(p).toLowerCase().includes(q)); $('multiPatientList').innerHTML=a.slice().reverse().map(p=>`<div class="patient-row"><b>${escapeHtml(p.name)}</b> • ${escapeHtml(p.village)}</br><span class="muted">${escapeHtml(p.phone||'-')} • ${escapeHtml(p.problem||'-')} • ${escapeHtml(p.time)}</span></div>`).join('')||'<p class="muted">No patients added</p>'; }
if($('addMultiPatient')) $('addMultiPatient').onclick=()=>{ const a=patients(); a.push({name:val('multiName')||'Patient', village:val('multiVillage')||'-', phone:val('multiPhone'), problem:val('multiProblem'), time:new Date().toLocaleString()}); savePatients(a); renderPatients(); speak(t('patientAdded')); };
if($('patientSearch')) $('patientSearch').oninput=renderPatients;
if($('exportPatients')) $('exportPatients').onclick=()=>{ const rows=['name,village,phone,problem,time',...patients().map(p=>[p.name,p.village,p.phone,p.problem,p.time].map(x=>`"${String(x||'').replaceAll('"','""')}"`).join(','))]; const blob=new Blob([rows.join('\n')],{type:'text/csv'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='patient_register.csv'; a.click(); };
async function renderPlusAnalytics(){
  try{ const logs=await (await fetch('/api/logs')).json(); const villages={}; logs.forEach(l=>{const v=l.patient?.village||'Unknown'; villages[v]=(villages[v]||0)+1}); const max=Math.max(1,...Object.values(villages)); if($('heatmapList')) $('heatmapList').innerHTML=Object.entries(villages).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([v,c])=>`<div class="heatmap-row" style="--w:${Math.round(c/max*100)}%"><span>${escapeHtml(v)}</span><b>${c}</b></div>`).join('')||'<p class="muted">No village data</p>'; const counts={critical:0,high:0,medium:0,low:0}; logs.forEach(l=>{const k=l.risk?.level_key||'low'; if(counts[k]!=null)counts[k]++}); const total=Math.max(1,logs.length); if($('riskTrendBars')) $('riskTrendBars').innerHTML=['critical','high','medium','low'].map(k=>`<div class="trend-row"><b>${k}</b><div class="trend-track"><div class="trend-fill ${k}" style="width:${Math.round(counts[k]/total*100)}%"></div></div><span>${counts[k]}</span></div>`).join(''); }catch(e){}
}
const oldRenderResult = renderResult;
renderResult = function(data){ oldRenderResult(data); renderMedicineReminders(data); renderPlusAnalytics(); };
const oldLoadLogs = loadLogs;
loadLogs = async function(){ await oldLoadLogs(); renderPlusAnalytics(); };
renderVideos(); renderPatients(); renderPlusAnalytics();



