const emergencyNumbers = [
  ['🚑','Ambulance','108'], ['👮','Police','100'], ['🔥','Fire','101'], ['👩','Women Helpline','1091'], ['🧒','Child Helpline','1098'], ['☠️','Poison Help','1066'], ['🏥','Health Helpline','104'], ['📞','Disaster Help','1077']
];
function renderEmergencyNumbers(){
  const box=$('emergencyNumbersGrid'); if(!box) return;
  box.innerHTML = emergencyNumbers.map(n=>`<div class="number-card"><b>${n[0]} ${n[1]}</b><a href="tel:${n[2]}">${n[2]}</a></div>`).join('');
}
function familyContacts(){ try{return JSON.parse(localStorage.getItem('familyContacts')||'[]')}catch(e){return[]} }
function saveFamilyContacts(a){ localStorage.setItem('familyContacts', JSON.stringify(a.slice(-10))); }
function renderFamilyContacts(){
  const box=$('familyContactList'); if(!box) return; const a=familyContacts();
  box.innerHTML = a.map((c,i)=>`<div class="family-row"><b>${escapeHtml(c.name)}</b> • ${escapeHtml(c.relation)}</br><span class="muted">${escapeHtml(c.phone)}</span><div><a class="mini-btn" href="tel:${encodeURIComponent(c.phone)}">📞 ${t('callHospital')}</a><button class="mini-btn" onclick="alertFamilyContact(${i})">📲 WhatsApp</button><button class="mini-btn danger-mini" onclick="removeFamilyContact(${i})">✕</button></div></div>`).join('') || `<p class="muted">${t('noContacts')}</p>`;
}
window.removeFamilyContact = i => { const a=familyContacts(); a.splice(i,1); saveFamilyContacts(a); renderFamilyContacts(); };
window.alertFamilyContact = i => { const c=familyContacts()[i]; if(!c) return; const txt=encodeURIComponent(makeWhatsAppText()); const phone=(c.phone||'').replace(/\D/g,''); window.open(`https://wa.me/${phone}?text=${txt}`,'_blank'); };
function addFamilyContact(){ const a=familyContacts(); a.push({name:val('familyName')||'Contact', relation:val('familyRelation')||'Family', phone:val('familyPhone')}); saveFamilyContacts(a); ['familyName','familyRelation','familyPhone'].forEach(id=>{ if($(id)) $(id).value=''; }); renderFamilyContacts(); speak(t('contactAdded')); }
function alertAllContacts(){ const a=familyContacts(); if(!a.length){alert(t('noContacts'));return;} a.forEach((c,idx)=>setTimeout(()=>window.alertFamilyContact(idx), idx*500)); }
if($('addFamilyContact')) $('addFamilyContact').onclick=addFamilyContact;
if($('alertAllContacts')) $('alertAllContacts').onclick=alertAllContacts;
if($('clearFamilyContacts')) $('clearFamilyContacts').onclick=()=>{localStorage.removeItem('familyContacts');renderFamilyContacts();};

function reportDataForPdf(){
  return Object.assign({}, lastResult||{}, {
    patient: getPayload(),
    selected_hospital: selectedHospital ? {name:selectedHospital.name, distance:selectedHospital.dist.toFixed(2)+' km', address:selectedHospital.addr||'', lat:selectedHospital.lat, lng:selectedHospital.lng} : null
  });
}
async function downloadPdfReport(){
  if(!lastResult){ alert(t('analyzeFirst')); return; }
  if($('pdfStatus')) $('pdfStatus').textContent = t('pdfPreparing');
  try{
    const res = await fetch('/api/pdf-report',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(reportDataForPdf())});
    if(!res.ok) throw new Error(await res.text());
    const blob = await res.blob(); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=`emergency_report_${lastResult.case_id||Date.now()}.pdf`; a.click();
    if($('pdfStatus')) $('pdfStatus').textContent = t('pdfDownloaded');
  }catch(e){ if($('pdfStatus')) $('pdfStatus').textContent = t('pdfFailed'); alert(t('pdfFailed')); }
}
function printEmergencyReport(){ if(!lastResult){alert(t('analyzeFirst'));return;} const w=window.open('','_blank'); w.document.write(`<pre style="font-family:Arial;white-space:pre-wrap;font-size:14px">${escapeHtml(reportText())}</pre>`); w.document.close(); w.print(); }
if($('downloadPdfReportBtn')) $('downloadPdfReportBtn').onclick=downloadPdfReport;
if($('printReportBtn')) $('printReportBtn').onclick=printEmergencyReport;
// Make existing download report buttons generate PDF, while text report remains available through saved history if needed.
if($('downloadReportBtn')) $('downloadReportBtn').onclick=downloadPdfReport;
if($('downloadPatientReportBtn')) $('downloadPatientReportBtn').onclick=downloadPdfReport;

function commandTextForLang(){ return t('commandHelp'); }
function runVoiceCommand(cmd){
  const c = (cmd||'').toLowerCase();
  if($('voiceCommandStatus')) $('voiceCommandStatus').textContent = '🎙️ ' + cmd;
  if(c.includes('hospital') || c.includes('ಆಸ್ಪತ್ರ') || c.includes('ఆసుపత్ర')){ scrollToId('locationSection'); if(selectedLocation) loadHospitals(); else getLiveLocation(); speak(t('findNearest')); return; }
  if(c.includes('108') || c.includes('emergency') || c.includes('ತುರ್ತು') || c.includes('అత్యవసర')){ window.location.href='tel:108'; speak(t('call108')); return; }
  if(c.includes('first') || c.includes('aid') || c.includes('ಪ್ರಥಮ') || c.includes('ఫస్ట్')){ scrollToId('guideSection'); speak((lastResult?.first_aid||[]).join('. ') || t('analyzeFirst')); return; }
  if(c.includes('medicine') || c.includes('ಔಷ') || c.includes('మంద')){ scrollToId('medicineSection'); speak((lastResult?.medicine_guidance?.suggestions||[]).join('. ') || t('analyzeFirst')); return; }
  if(c.includes('dashboard') || c.includes('ಡ್ಯಾಶ್') || c.includes('డ్యాష్')){ scrollToId('dashboardSection'); loadLogs(); speak(t('dashboard')); return; }
  speak(t('commandNotUnderstood'));
}
window.runVoiceCommand=runVoiceCommand;
function startVoiceCommand(){ const SR=window.SpeechRecognition||window.webkitSpeechRecognition; if(!SR){alert(t('voiceNotSupported'));return;} const rec=new SR(); rec.lang=currentLang==='kn'?'kn-IN':currentLang==='te'?'te-IN':'en-IN'; rec.interimResults=false; rec.continuous=false; if($('voiceCommandStatus')) $('voiceCommandStatus').textContent=t('listening'); rec.start(); rec.onresult=e=>runVoiceCommand(e.results[0][0].transcript); rec.onerror=e=>{ if($('voiceCommandStatus')) $('voiceCommandStatus').textContent=t('voiceError')+': '+e.error; }; }
if($('voiceCommandBtn')) $('voiceCommandBtn').onclick=startVoiceCommand;
if($('speakCommandsBtn')) $('speakCommandsBtn').onclick=()=>speak(commandTextForLang());


// Re-apply language placeholders for newly added sections and render new widgets.
const previousApplyLanguage = applyLanguage;
applyLanguage = function(){ previousApplyLanguage(); renderEmergencyNumbers(); renderFamilyContacts(); };
renderEmergencyNumbers(); renderFamilyContacts(); applyLanguage();
